mapper.select:
select b.log_id, b.member_id, b.product_id, b.product_name, b.category_id, b.source, b.create_time
from shop_browsing_logs b
inner join (
    select product_id, max(log_id) as max_log_id
    from shop_browsing_logs
    where member_id = #{memberId}
    group by product_id
) latest on b.log_id = latest.max_log_id
order by b.create_time desc
limit #{limit}

mapper.update:
UPDATE shop_browsing_logs
SET member_id = #{memberId}, guest_id = NULL
WHERE guest_id = #{guestId}
